import React, { useEffect, useState } from 'react';
import { db } from '../firebase';
import { collection, getDocs } from 'firebase/firestore';
import { FaWhatsapp } from 'react-icons/fa';
import { useNavigate } from 'react-router-dom';

function SetGame() {
  const [games, setGames] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchGames = async () => {
      try {
        const gamesCollection = await getDocs(collection(db, 'games'));
        const gamesData = gamesCollection.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setGames(gamesData);
      } catch (error) {
        console.error('Error fetching games:', error);
      }
    };

    fetchGames();
  }, []);

  const handleCreateTeam = (gameId) => {
    navigate(`/create-team/${gameId}`);
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Set Game</h1>
      <div style={styles.gameList}>
        {games.length > 0 ? (
          games.map((game) => (
            <div key={game.id} style={styles.gameCard}>
              <p><strong>Location:</strong> {game.location}</p>
              <p><strong>Date:</strong> {game.date}</p>
              <p><strong>Time:</strong> {game.time}</p>
              {game.whatsappLink && (
                <a href={game.whatsappLink} target="_blank" rel="noopener noreferrer" style={styles.whatsappIcon}>
                  <FaWhatsapp size={24} />
                </a>
              )}
              <button style={styles.button} onClick={() => handleCreateTeam(game.id)}>
                Create Team
              </button>
            </div>
          ))
        ) : (
          <p style={styles.noGames}>No games available.</p>
        )}
      </div>
      <button style={styles.backButton} onClick={() => navigate('/')}>Back to Main Menu</button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
  },
  title: {
    fontSize: '24px',
    color: '#293F14',
    textShadow: '2px 2px #7FC6A4',
    marginBottom: '30px',
  },
  gameList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
    width: '80%',
  },
  gameCard: {
    backgroundColor: '#7FC6A4',
    padding: '20px',
    borderRadius: '10px',
    border: '2px solid #5D737E',
    boxShadow: '3px 3px #386C0B',
  },
  whatsappIcon: {
    color: '#25D366',
    textDecoration: 'none',
    marginTop: '10px',
  },
  button: {
    backgroundColor: '#386C0B',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    border: '2px solid #5D737E',
    cursor: 'pointer',
    fontSize: '14px',
    boxShadow: '2px 2px #7FC6A4',
    marginTop: '10px',
  },
  backButton: {
    marginTop: '30px',
    backgroundColor: '#5D737E',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    border: '2px solid #293F14',
    cursor: 'pointer',
    fontSize: '14px',
  },
  noGames: {
    fontSize: '14px',
    color: '#293F14',
  },
};

export default SetGame;
